var fileJSON=[{"path":"/home/yere-tft/Escritorio/TFT2026/CNN/PruebasMotorNeuronal/fpga/engineCNN.cl", "name":"engineCNN.cl", "has_active_debug_locs":true, "absName":"/home/yere-tft/Escritorio/TFT2026/CNN/PruebasMotorNeuronal/fpga/engineCNN.cl", "content":"// ============================================================================\012// ACELERADOR DE REDES NEURONALES INT8 - INTEL FPGA (CYCLONE V)\012// ============================================================================\012#pragma OPENCL EXTENSION cl_intel_channels : enable\012\012channel uchar ch_in __attribute__((depth(32)));\012channel uchar ch_out __attribute__((depth(32)));\012\012// 🔥 TILING AJUSTADO A 16 (Garantiza el 100% de éxito en el enrutamiento)\012#define TILE_OUT_C 16\012#define MAX_W_PER_OC 9216 \012\012// ============================================================================\012// KERNEL 1: LECTURA DE MEMORIA EXTERNA \012// ============================================================================\012__attribute__((max_global_work_dim(0))) \012__kernel void mem_read_generic(\012    __global const uchar* restrict mem_in,\012    int in_offset, int w, int h, int in_c, int stride, int pad, uchar x_zero)\012{\012    // 🔥 OPTIMIZACIÓN 1: Cero Divisiones Hardware (Uso de Bit Shift para stride 2)\012    int tmp_h = h + 2 * pad - 3;\012    int tmp_w = w + 2 * pad - 3;\012    int out_h = (stride == 2 ? (tmp_h >> 1) : tmp_h) + 1;\012    int out_w = (stride == 2 ? (tmp_w >> 1) : tmp_w) + 1;\012\012    // 🔥 OPTIMIZACIÓN 2: Precalcular constantes fuera del bucle\012    int w_in_c = w * in_c;\012\012    #pragma unroll 1\012    for (int oy = 0; oy < out_h; oy++) {\012        #pragma unroll 1\012        for (int ox = 0; ox < out_w; ox++) {\012            #pragma unroll 1\012            for (int ky = 0; ky < 3; ky++) {\012                #pragma unroll 1\012                for (int kx = 0; kx < 3; kx++) {\012                    \012                    int iy = oy * stride - pad + ky;\012                    int ix = ox * stride - pad + kx;\012                    bool out_of_bounds = (iy < 0 || iy >= h || ix < 0 || ix >= w);\012\012                    // Índice base calculado con sumas baratas\012                    int base_idx = in_offset + iy * w_in_c + ix * in_c;\012\012                    #pragma unroll 1\012                    for (int c = 0; c < in_c; c++) {\012                        uchar val = x_zero;\012                        if (!out_of_bounds) {\012                            val = mem_in[base_idx + c];\012                        }\012                        write_channel_intel(ch_in, val);\012                    }\012                }\012            }\012        }\012    }\012}\012\012// ============================================================================\012// KERNEL 2: MOTOR MATEMÁTICO (CONVOLUCIÓN INT8)\012// ============================================================================\012__attribute__((max_global_work_dim(0)))\012__kernel void conv_generic(\012    __global const uchar* restrict weights,\012    __global const int* restrict bias,\012    int w_off, int b_off, int w, int h, int in_c, int tile_channels,\012    int stride, int pad, uchar x_zero, uchar w_zero, int y_zero,\012    int M_mult, int M_shift)\012{\012    int tmp_h = h + 2 * pad - 3;\012    int tmp_w = w + 2 * pad - 3;\012    int out_h = (stride == 2 ? (tmp_h >> 1) : tmp_h) + 1;\012    int out_w = (stride == 2 ? (tmp_w >> 1) : tmp_w) + 1;\012\012    int local_bias[TILE_OUT_C];\012    #pragma unroll 1\012    for(int oc = 0; oc < TILE_OUT_C; oc++) {\012        if (oc < tile_channels) local_bias[oc] = bias[(b_off / 4) + oc]; \012    }\012\012    // 🔥 OPTIMIZACIÓN 3: Obligar a usar 1 solo banco RAM para ahorrar ALUTs de ruteo\012    __local uchar local_W[TILE_OUT_C][MAX_W_PER_OC] __attribute__((memory, numbanks(1)));\012    \012    int limit = 3 * 3 * in_c;\012    #pragma unroll 1\012    for (int oc = 0; oc < TILE_OUT_C; oc++) {\012        if (oc < tile_channels) {\012            int base_w = w_off + oc * limit;\012            #pragma unroll 1\012            for (int i = 0; i < limit; i++) {\012                local_W[oc][i] = weights[base_w + i];\012            }\012        }\012    }\012\012    #pragma unroll 1\012    for (int oy = 0; oy < out_h; oy++) {\012        #pragma unroll 1\012        for (int ox = 0; ox < out_w; ox++) {\012\012            int acc[TILE_OUT_C];\012            #pragma unroll\012            for (int oc = 0; oc < TILE_OUT_C; oc++) {\012                acc[oc] = 0;\012            }\012\012            int w_idx = 0; \012            \012            #pragma unroll 1\012            for (int ky = 0; ky < 3; ky++) {\012                #pragma unroll 1\012                for (int kx = 0; kx < 3; kx++) {\012                    #pragma unroll 1\012                    for (int c = 0; c < in_c; c++) {\012                        \012                        uchar px = read_channel_intel(ch_in);\012                        int px_val = (int)px - (int)x_zero;\012\012                        #pragma unroll\012                        for (int oc = 0; oc < TILE_OUT_C; oc++) {\012                            if (oc < tile_channels) {\012                                int w_val = (int)local_W[oc][w_idx] - (int)w_zero;\012                                acc[oc] += px_val * w_val;\012                            }\012                        }\012                        w_idx++; \012                    }\012                }\012            }\012\012            #pragma unroll 1\012            for (int oc = 0; oc < tile_channels; oc++) {\012                int res = acc[oc] + local_bias[oc];\012                long long res_mult = (long long)res * (long long)M_mult;\012                int q_res = 0;\012\012                if (M_shift > 0) {\012                    long long nudge = 1LL << (M_shift - 1); \012                    q_res = (int)((res_mult + nudge) >> M_shift);\012                } else {\012                    q_res = (int)res_mult;\012                }\012\012                q_res += y_zero;\012                if (q_res < 0) q_res = 0;\012                if (q_res > 255) q_res = 255;\012\012                write_channel_intel(ch_out, (uchar)q_res);\012            }\012        }\012    }\012}\012\012// ============================================================================\012// KERNEL 3: ESCRITURA EN MEMORIA EXTERNA\012// ============================================================================\012__attribute__((max_global_work_dim(0)))\012__kernel void mem_write_generic(\012    __global uchar* restrict mem_out,\012    int out_offset, int w, int h, int out_c, int tile_channels, int t_offset,\012    int stride, int pad)\012{\012    int tmp_h = h + 2 * pad - 3;\012    int tmp_w = w + 2 * pad - 3;\012    int out_h = (stride == 2 ? (tmp_h >> 1) : tmp_h) + 1;\012    int out_w = (stride == 2 ? (tmp_w >> 1) : tmp_w) + 1;\012\012    int current_out_idx = out_offset + t_offset; \012\012    #pragma unroll 1\012    for (int oy = 0; oy < out_h; oy++) {\012        #pragma unroll 1\012        for (int ox = 0; ox < out_w; ox++) {\012            #pragma unroll 1\012            for (int oc = 0; oc < tile_channels; oc++) {\012                uchar val = read_channel_intel(ch_out);\012                mem_out[current_out_idx + oc] = val;\012            }\012            current_out_idx += out_c; \012        }\012    }\012}"}];